'use server';

/**
 * 娓犻亾绛夌骇鎶樻墸 Server Actions
 *
 * 鎻愪緵娓犻亾绛夌骇鎶樻墸鐨勯厤缃鐞嗗姛鑳斤細
 * - 鍏ㄥ眬榛樿鎶樻墸閰嶇疆锛堝瓨鍌ㄥ湪 tenants.settings锛塡r
 * - 鍝佺被/鍟嗗搧瑕嗙洊瑙勫垯锛堝瓨鍌ㄥ湪 channel_discount_overrides 琛級
 */

import { db } from '@/shared/api/db';
import { channelDiscountOverrides } from '@/shared/api/schema/supply-chain';
import { tenants } from '@/shared/api/schema/infrastructure';
import { eq, and, desc } from 'drizzle-orm';
import { auth } from '@/shared/lib/auth';
import { revalidatePath, revalidateTag, unstable_cache, updateTag } from 'next/cache';
import { z } from 'zod';
import { AuditService } from '@/shared/services/audit-service';

// =============================================
// Schema 瀹氫箟
// =============================================

/**
 * 鍏ㄥ眬鎶樻墸閰嶇疆 Schema
 */
const globalDiscountSchema = z.object({
  sLevel: z.number().min(0).max(200),
  aLevel: z.number().min(0).max(200),
  bLevel: z.number().min(0).max(200),
  cLevel: z.number().min(0).max(200),
  // 鐗规畩瑙勫垯
  packageNoDiscount: z.boolean().optional(),
  bundleSeparateDiscount: z.boolean().optional(),
});

/**
 * 瑕嗙洊瑙勫垯 Schema
 */
const overrideSchema = z.object({
  scope: z.enum(['CATEGORY', 'PRODUCT']),
  targetId: z.string().min(1),
  targetName: z.string().optional(),
  sLevelDiscount: z.number().min(0).max(200).optional(),
  aLevelDiscount: z.number().min(0).max(200).optional(),
  bLevelDiscount: z.number().min(0).max(200).optional(),
  cLevelDiscount: z.number().min(0).max(200).optional(),
});

// =============================================
// 杈呭姪鍑芥暟
// =============================================

/**
 * 鑾峰彇褰撳墠鐢ㄦ埛鐨?tenantId
 */
async function getTenantIdFromSession(): Promise<string> {
  const session = await auth();
  if (!session?.user?.tenantId) {
    throw new Error('鏈巿鏉冭闂?);
  }
  return session.user.tenantId;
}

// =============================================
// 鍏ㄥ眬鎶樻墸閰嶇疆
// =============================================

/**
 * 鑾峰彇鍏ㄥ眬娓犻亾鎶樻墸閰嶇疆锛堝唴閮ㄧ紦瀛?wrapper锛塡r
 *
 * @description 浣跨敤 unstable_cache 鎸?tenantId 缂撳瓨锛宼ag: global-discount / global-discount-{tenantId}
 * 鍏ㄥ眬鎶樻墸鏄绠楁姤浠风殑鍩虹璇诲彇锛屽彉鍔ㄥ懆鏈熼暱锛岄€傚悎缂撳瓨銆俓r
 * 淇敼閰嶇疆鏃堕€氳繃 revalidateTag('global-discount') 澶辨晥銆俓r
 *
 * @param tenantId - 褰撳墠绉熸埛 ID
 * @returns 瀵瑰簲绉熸埛鐨勫叏灞€绾у埆鎶樻墸璁＄畻瑙勫垯鍙婂弬鏁伴厤缃甛r
 */
const getCachedGlobalDiscountConfig = (tenantId: string) =>
  unstable_cache(
    async () => {
      const tenant = await db.query.tenants.findFirst({
        where: eq(tenants.id, tenantId),
      });

      if (!tenant) {
        throw new Error('绉熸埛涓嶅瓨鍦?);
      }

      const settings = (tenant.settings as Record<string, unknown>) || {};
      const discountConfig = (settings.channelDiscounts as Record<string, unknown>) || {};

      return {
        sLevel: Number(discountConfig.sLevel) || 95,
        aLevel: Number(discountConfig.aLevel) || 98,
        bLevel: Number(discountConfig.bLevel) || 100,
        cLevel: Number(discountConfig.cLevel) || 102,
        packageNoDiscount: Boolean(discountConfig.packageNoDiscount),
        bundleSeparateDiscount: Boolean(discountConfig.bundleSeparateDiscount),
      };
    },
    [`global-discount-${tenantId}`],
    { tags: ['global-discount', `global-discount-${tenantId}`] }
  );

/**
 * 鑾峰彇鍏ㄥ眬娓犻亾鎶樻墸閰嶇疆
 *
 * @description 鑾峰彇褰撳墠绉熸埛鍏ㄥ眬鐢熸晥鐨勬笭閬撶骇鍒姌鎵ｉ厤姣旓紙宸蹭娇鐢?unstable_cache 缂撳瓨锛夈€俓r
 *
 * @returns 鍏ㄥ眬閫氶亾棰勬病鐨勬姌鎵ｈ鍒欏拰绛夌骇姊鎶樼巼
 * @throws 褰撴棤鏈夋晥绉熸埛鏃舵姤閿橽r
 */
export async function getGlobalDiscountConfig() {
  try {
    const tenantId = await getTenantIdFromSession();
    return { data: await getCachedGlobalDiscountConfig(tenantId)() };
  } catch (error) {
    return { error: error instanceof Error ? error.message : '鑾峰彇閰嶇疆澶辫触' };
  }
}

/**
 * 鏇存柊鍏ㄥ眬娓犻亾鎶樻墸閰嶇疆
 *
 * @description 璋冩暣绉熸埛瑙嗚涓嬪鏁翠綋鎶樻墸鏋舵瀯姊害鐨勯璁炬暟鍊笺€傛寔涔呭寲杩涘叆 settings 鐨?JSON 涔嬩腑锛屽悓鏃跺悐閿€杩囧線閰嶇疆缂撳瓨銆俓r
 *
 * @param input - 绗﹀悎 `globalDiscountSchema` 鐨勫畬鏁存笭閬撶粨鏋勯厤缃ā鍨媆r
 * @returns 淇敼纭瀵硅薄鍐呭
 */
export async function updateGlobalDiscountConfig(input: z.infer<typeof globalDiscountSchema>) {
  try {
    const tenantId = await getTenantIdFromSession();
    const validated = globalDiscountSchema.parse(input);

    // 鑾峰彇褰撳墠 settings
    const tenant = await db.query.tenants.findFirst({
      where: eq(tenants.id, tenantId),
    });

    if (!tenant) {
      throw new Error('绉熸埛涓嶅瓨鍦?);
    }

    const currentSettings = (tenant.settings as Record<string, unknown>) || {};

    // 鏇存柊 channelDiscounts 閰嶇疆
    await db
      .update(tenants)
      .set({
        settings: {
          ...currentSettings,
          channelDiscounts: validated,
        },
        updatedAt: new Date(),
      })
      .where(eq(tenants.id, tenantId));

    await AuditService.log(db, {
      tenantId,
      userId: 'system', // 閰嶇疆绫绘洿鏂版殏鐢?system 鏍囪瘑
      tableName: 'tenants',
      recordId: tenantId,
      action: 'UPDATE',
      oldValues: { channelDiscounts: currentSettings.channelDiscounts },
      newValues: { channelDiscounts: validated },
      details: { action: 'UPDATE_GLOBAL_DISCOUNT' },
    });

    // 澶辨晥鍏ㄥ眬鎶樻墸缂撳瓨
    updateTag(`global-discount-${tenantId}`);
    revalidatePath('/settings/products');
    return { success: true };
  } catch (error) {
    return { error: error instanceof Error ? error.message : '鏇存柊閰嶇疆澶辫触' };
  }
}

// =============================================
// 瑕嗙洊瑙勫垯绠＄悊
// =============================================

/**
 * 鑾峰彇鎵€鏈夎鐩栬鍒橽r
 *
 * @description 璇诲彇褰撳墠绉熸埛鐨勬墍鏈夌壒渚嬫墦鎶樿鍒欙紝鍚檺瀹氫簬灞€閮ㄥ晢鍝佹垨鐗瑰畾鍝佺被鐨勯檷浠烽€昏緫銆俓r
 *
 * @returns 鎶樻墸鐗逛緥瑕嗗啓琛ㄥ畬鏁存竻鍗昞r
 */
export async function getDiscountOverrides() {
  try {
    const tenantId = await getTenantIdFromSession();

    const overrides = await db
      .select()
      .from(channelDiscountOverrides)
      .where(eq(channelDiscountOverrides.tenantId, tenantId))
      .orderBy(desc(channelDiscountOverrides.createdAt));

    return { data: overrides };
  } catch (error) {
    return { error: error instanceof Error ? error.message : '鑾峰彇瑕嗙洊瑙勫垯澶辫触' };
  }
}

/**
 * 鍒涘缓瑕嗙洊瑙勫垯
 *
 * @description 鏂板閽堝鍗曚竴鍝佺被鎴栦笓闂ㄦ煇涓晢鍝佺殑閫氶亾瑕嗙洊鍨嬫墦鎶橀妗堬紝璁板綍鏂板娲诲姩鏃ュ織銆俓r
 *
 * @param input - 绗﹀悎 `overrideSchema` 缁撴瀯鐨勬柊寤哄叆鍙傛ā鍨媆r
 * @returns 琚彃鍏ュ簱鐨勮褰曞璞″拰鍒嗛厤鐨勭嫭绔嬫爣璇哱r
 */
export async function createDiscountOverride(input: z.infer<typeof overrideSchema>) {
  try {
    const tenantId = await getTenantIdFromSession();
    const validated = overrideSchema.parse(input);

    // 妫€鏌ユ槸鍚﹀凡瀛樺湪鐩稿悓鐨勮鐩栬鍒橽r
    const existing = await db.query.channelDiscountOverrides.findFirst({
      where: and(
        eq(channelDiscountOverrides.tenantId, tenantId),
        eq(channelDiscountOverrides.scope, validated.scope),
        eq(channelDiscountOverrides.targetId, validated.targetId)
      ),
    });

    if (existing) {
      throw new Error('璇ヨ鐩栬鍒欏凡瀛樺湪');
    }

    const [override] = await db
      .insert(channelDiscountOverrides)
      .values({
        tenantId,
        scope: validated.scope,
        targetId: validated.targetId,
        targetName: validated.targetName,
        sLevelDiscount: validated.sLevelDiscount?.toString(),
        aLevelDiscount: validated.aLevelDiscount?.toString(),
        bLevelDiscount: validated.bLevelDiscount?.toString(),
        cLevelDiscount: validated.cLevelDiscount?.toString(),
      })
      .returning();

    await AuditService.log(db, {
      tenantId,
      userId: 'system',
      tableName: 'channel_discount_overrides',
      recordId: override.id,
      action: 'CREATE',
      newValues: override,
    });

    revalidatePath('/settings/products');
    return { data: override };
  } catch (error) {
    return { error: error instanceof Error ? error.message : '鍒涘缓瑕嗙洊瑙勫垯澶辫触' };
  }
}

/**
 * 鏇存柊瑕嗙洊瑙勫垯
 *
 * @description 淇敼鐜板瓨鐨勪笉閫傜敤澶т紬鏍囧噯璁′环鏃剁殑鐗规畩瑕嗙洊鎶樻墸瑙勫垯妗ｄ綅锛屽苟鍚屾椂璁板綍鍙樻洿鍓嶄笌鍙樻洿鍚庢暟鎹€俓r
 *
 * @param id - 闇€瑕佺紪杈戣皟鏁寸殑鐗规瑕嗙洊瑙勫垯鐨勬爣蹇椾唬鐮乗r
 * @param input - 鏇存柊鐨勯€氶亾鍜岃鍒欓泦鍚圽r
 * @returns 鏄惁鍙樻洿鎴愬姛鐨勭姸鎬佹爣瀹歕r
 * @throws 鎸囧畾鏍囧彿鎴栫壒渚嬭绔犲湪搴撳綋涓苟涓嶅瓨鍦ㄧ殑鎯呭喌
 */
export async function updateDiscountOverride(
  id: string,
  input: Partial<z.infer<typeof overrideSchema>>
) {
  try {
    const tenantId = await getTenantIdFromSession();

    // 楠岃瘉瑙勫垯瀛樺湪涓斿睘浜庡綋鍓嶇鎴穃r
    const existing = await db.query.channelDiscountOverrides.findFirst({
      where: and(
        eq(channelDiscountOverrides.id, id),
        eq(channelDiscountOverrides.tenantId, tenantId)
      ),
    });

    if (!existing) {
      throw new Error('瑕嗙洊瑙勫垯涓嶅瓨鍦?);
    }

    const [updated] = await db
      .update(channelDiscountOverrides)
      .set({
        ...(input.targetName !== undefined && { targetName: input.targetName }),
        ...(input.sLevelDiscount !== undefined && {
          sLevelDiscount: input.sLevelDiscount.toString(),
        }),
        ...(input.aLevelDiscount !== undefined && {
          aLevelDiscount: input.aLevelDiscount.toString(),
        }),
        ...(input.bLevelDiscount !== undefined && {
          bLevelDiscount: input.bLevelDiscount.toString(),
        }),
        ...(input.cLevelDiscount !== undefined && {
          cLevelDiscount: input.cLevelDiscount.toString(),
        }),
        updatedAt: new Date(),
      })
      .where(eq(channelDiscountOverrides.id, id))
      .returning();

    await AuditService.log(db, {
      tenantId,
      userId: 'system',
      tableName: 'channel_discount_overrides',
      recordId: updated.id,
      action: 'UPDATE',
      newValues: input,
      oldValues: { id },
    });

    revalidatePath('/settings/products');
    return { data: updated };
  } catch (error) {
    return { error: error instanceof Error ? error.message : '鏇存柊瑕嗙洊瑙勫垯澶辫触' };
  }
}

/**
 * 鍒犻櫎瑕嗙洊瑙勫垯
 *
 * @description 搴熼櫎姝ょ壒渚嬭鐩栬鍒欍€佹墽琛岀墿鐞嗙骇鍒犻櫎鍔ㄤ綔骞朵綔瀹¤淇濈暀銆傝涓讳綋鍙婂叾绫诲埆鐨勬墍鏈夋墦鎶橀€氶亾璁＄畻閮藉皢鎶樿繑涓哄叏灞€鍩虹榛樿鎵撴姌鍔涘害銆俓r
 *
 * @param id - 鍑嗕簣鎶归櫎鐨勮瑕嗙洊鏉″垯搴忓垪涓婚敭
 * @returns 纭€ф秷闄よ褰曠粨鏋滅殑甯冨皵鍨嬭緭鍑烘爣璇哱r
 */
export async function deleteDiscountOverride(id: string) {
  try {
    const tenantId = await getTenantIdFromSession();

    // 楠岃瘉瑙勫垯瀛樺湪涓斿睘浜庡綋鍓嶇鎴穃r
    const existing = await db.query.channelDiscountOverrides.findFirst({
      where: and(
        eq(channelDiscountOverrides.id, id),
        eq(channelDiscountOverrides.tenantId, tenantId)
      ),
    });

    if (!existing) {
      throw new Error('瑕嗙洊瑙勫垯涓嶅瓨鍦?);
    }

    await db.delete(channelDiscountOverrides).where(eq(channelDiscountOverrides.id, id));

    await AuditService.log(db, {
      tenantId,
      userId: 'system',
      tableName: 'channel_discount_overrides',
      recordId: id,
      action: 'DELETE',
      oldValues: { id },
    });

    revalidatePath('/settings/products');
    return { success: true };
  } catch (error) {
    return { error: error instanceof Error ? error.message : '鍒犻櫎瑕嗙洊瑙勫垯澶辫触' };
  }
}

// =============================================
// 鎶樻墸璁＄畻杈呭姪
// =============================================

/**
 * 鑾峰彇鍟嗗搧鐨勬渶缁堟姌鎵ｇ巼
 *
 * @description 閬靛惊鐗瑰畾浼樹簬鏅€氱殑涓氬姟鍐崇瓥浼樺厛閾捐矾锛屼紭鍏堢骇锛氬晢鍝佺骇瑕嗙洊 > 鍝佺被绾ц鐩?> 鍏ㄥ眬榛樿
 *
 * @param productId - 鎵€闇€瀹氬ず鍟嗗搧 ID
 * @param category - 璇ュ晢鍝侀檮闅忔墍灞炵被鐩紙鐢ㄤ簬鏌ラ槄鍝佺被灞傝鐩栬鍒讹級
 * @param channelLevel - 閫氶亾瀵瑰簲鐧昏鏍囧害 ('S' | 'A' | 'B' | 'C')
 * @returns 瀹炴椂鐨勩€佹渶缁堜綔鐢ㄥ畾澶烘娆惧晢鍝佺殑绮剧‘绠楃巼缁撴灉銆傛壘涓嶅埌杩斿洖缂轰綅鍗犱綅榛樿鍊硷紙100琛ㄧず涓嶆墦鎶樺叏浠凤級銆俓r
 */
export async function getProductDiscountRate(
  productId: string,
  category: string,
  channelLevel: 'S' | 'A' | 'B' | 'C'
) {
  try {
    const tenantId = await getTenantIdFromSession();

    // 1. 鑾峰彇鍏ㄥ眬閰嶇疆
    const globalResult = await getGlobalDiscountConfig();
    if (globalResult.error) {
      throw new Error(globalResult.error);
    }
    const globalConfig = globalResult.data!;

    // 2. 鏌ユ壘鍟嗗搧绾ц鐩朶r
    const productOverride = await db.query.channelDiscountOverrides.findFirst({
      where: and(
        eq(channelDiscountOverrides.tenantId, tenantId),
        eq(channelDiscountOverrides.scope, 'PRODUCT'),
        eq(channelDiscountOverrides.targetId, productId),
        eq(channelDiscountOverrides.isActive, true)
      ),
    });

    if (productOverride) {
      const levelKey = `${channelLevel.toLowerCase()}LevelDiscount` as keyof typeof productOverride;
      const discount = productOverride[levelKey];
      if (discount !== null && discount !== undefined) {
        return { data: Number(discount) };
      }
    }

    // 3. 鏌ユ壘鍝佺被绾ц鐩朶r
    const categoryOverride = await db.query.channelDiscountOverrides.findFirst({
      where: and(
        eq(channelDiscountOverrides.tenantId, tenantId),
        eq(channelDiscountOverrides.scope, 'CATEGORY'),
        eq(channelDiscountOverrides.targetId, category),
        eq(channelDiscountOverrides.isActive, true)
      ),
    });

    if (categoryOverride) {
      const levelKey =
        `${channelLevel.toLowerCase()}LevelDiscount` as keyof typeof categoryOverride;
      const discount = categoryOverride[levelKey];
      if (discount !== null && discount !== undefined) {
        return { data: Number(discount) };
      }
    }

    // 4. 杩斿洖鍏ㄥ眬榛樿
    const globalKey = `${channelLevel.toLowerCase()}Level` as keyof typeof globalConfig;
    return { data: globalConfig[globalKey] as number };
  } catch (error) {
    return { error: error instanceof Error ? error.message : '鑾峰彇鎶樻墸鐜囧け璐? };
  }
}

import {
    FormControl,
    FormDescription,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from '@/shared/ui/form';
import { Input } from '@/shared/ui/input';
import { UseFormReturn } from 'react-hook-form';
import { ProductFormValues } from '../schema';
import { CategorySchema } from '@/shared/api/schema/product';

interface ProductDynamicAttributesProps {
    form: UseFormReturn<ProductFormValues>;
    dynamicAttributes: CategorySchema['templateSchema'];
}

export function ProductDynamicAttributes({ form, dynamicAttributes }: ProductDynamicAttributesProps) {
    if (!dynamicAttributes || dynamicAttributes.length === 0) return null;

    return (
        <section className="space-y-4">
            <h3 className="border-l-4 border-indigo-500 pl-2 text-sm font-semibold">鎵╁睍灞炴€?/h3>
            <div className="grid grid-cols-2 gap-4">
                {dynamicAttributes.map((attr) => (
                    <FormField
                        key={attr.key}
                        control={form.control}
                        name={`attributes.${attr.key}` as "attributes"}
                        render={({ field }) => (
                            <FormItem>
                                <FormLabel>
                                    {attr.label}
                                    {attr.required && <span className="text-destructive ml-1">*</span>}
                                </FormLabel>
                                <FormControl>
                                    <Input
                                        type={attr.type === 'NUMBER' ? 'number' : 'text'}
                                        placeholder={`杈撳叆${attr.label}`}
                                        {...field}
                                        value={(field.value as string | number) || ''}
                                        onChange={(e) => {
                                            const val = e.target.value;
                                            if (attr.type === 'NUMBER') {
                                                field.onChange(val === '' ? undefined : Number(val));
                                            } else {
                                                field.onChange(val);
                                            }
                                        }}
                                    />
                                </FormControl>
                                <FormMessage />
                            </FormItem>
                        )}
                    />
                ))}
            </div>
        </section>
    );
}

import {
    FormControl,
    FormDescription,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from '@/shared/ui/form';
import { Input } from '@/shared/ui/input';
import { Badge } from '@/shared/ui/badge';
import { UseFormReturn } from 'react-hook-form';
import { ProductFormValues } from '../schema';
import { AlertCircle, TrendingDown, TrendingUp } from 'lucide-react';

interface ProductPriceAndProfitProps {
    form: UseFormReturn<ProductFormValues>;
    getProfitMargin: (cost: number, price: number) => { value: number; danger: boolean };
}

export function ProductPriceAndProfit({ form, getProfitMargin }: ProductPriceAndProfitProps) {
