'use client';

import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { Form } from '@/shared/ui/form';
import { Button } from '@/shared/ui/button';
import { ProductFormValues, productFormSchema } from './schema';
import { Product } from '@/shared/api/schema/product';
import { Loader2 } from 'lucide-react';
import { useProductForm } from '../hooks/use-product-form';
import { ProductBasicInfo } from './product-form-sections/product-basic-info';
import { ProductCategorySpecs } from './product-form-sections/product-category-specs';
import { ProductDynamicAttributes } from './product-form-sections/product-dynamic-attributes';
import { ProductPriceAndProfit } from './product-form-sections/product-price-and-profit';
import { ProductSupplyAndInventory } from './product-form-sections/product-supply-and-inventory';
import { ProductGallery } from './product-form-sections/product-gallery';

interface ProductFormProps {
  initialData?: Product;
  onSubmit: (values: ProductFormValues) => Promise<void>;
  onCancel?: () => void;
  isLoading?: boolean;
}

export function ProductForm({
  initialData,
  onSubmit,
  onCancel,
  isLoading,
}: ProductFormProps) {
  // 1. Initialize the form via React Hook Form.
  const form = useForm<ProductFormValues>({
    resolver: zodResolver(productFormSchema),
    defaultValues: initialData || {
      name: '',
      sku: '',
      categoryId: '',
      description: '',
      unit: '',
      defaultCost: 0,
      safeStock: 0,
      prices: {},
      attributes: {},
      images: [],
    },
  });

  // 2. Utilize the custom hook to handle business logic and state.
  const {
    isWallcloth,
    isWallpaper,
    hasCurtainSpecs,
    hidePurchaseType,
    dynamicAttributes,
    suppliers,
    styleInput,
    setStyleInput,
    currentStyles,
    addStyle,
    removeStyle,
    patternInput,
    setPatternInput,
    currentPatterns,
    addPattern,
    removePattern,
    getProfitMargin,
  } = useProductForm({
    categoryId: form.watch('categoryId'),
    attributes: form.watch('attributes'),
    onAttributesChange: (newAttributes) => {
      form.setValue('attributes', newAttributes);
    },
  });

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
        <ProductBasicInfo
          form={form}
          hidePurchaseType={hidePurchaseType}
          styleInput={styleInput}
          setStyleInput={setStyleInput}
          currentStyles={currentStyles}
          addStyle={addStyle}
          removeStyle={removeStyle}
        />

        <ProductCategorySpecs
          form={form}
          hasCurtainSpecs={hasCurtainSpecs}
          isWallcloth={isWallcloth}
          isWallpaper={isWallpaper}
          currentPatterns={currentPatterns}
          addPattern={addPattern}
          removePattern={removePattern}
          patternInput={patternInput}
          setPatternInput={setPatternInput}
        />

        <ProductDynamicAttributes form={form} dynamicAttributes={dynamicAttributes} />

        <ProductSupplyAndInventory form={form} suppliers={suppliers} />

        <ProductPriceAndProfit form={form} getProfitMargin={getProfitMargin} />

        <ProductGallery form={form} />

        {/* 搴曢儴鎿嶄綔鎸夐挳 */}
        <div className="flex justify-end gap-2 pt-4">
          <Button type="button" variant="outline" onClick={onCancel}>
            鍙栨秷
          </Button>
          <Button type="submit" disabled={isLoading}>
            {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            {initialData ? '淇濆瓨' : '鍒涘缓'}
          </Button>
        </div>
      </form>
    </Form>
  );
}

import { useState, useEffect, useCallback, useMemo } from 'react';
import { useForm, type Resolver } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { createProductSchema, updateProductSchema } from '../schema';
import { z } from 'zod';
import { toast } from 'sonner';
import { logger } from '@/shared/lib/logger';
import { getSuppliers } from '@/features/supply-chain/actions/supplier-actions';

export type ProductFormValues = z.infer<typeof createProductSchema> & { id?: string };

export interface AttributeField {
    key: string;
    label: string;
    type: 'STRING' | 'NUMBER' | 'BOOLEAN' | 'SELECT';
    required: boolean;
    options?: string[];
    unit?: string;
    placeholder?: string;
}

export const CATEGORY_TABS = [
    { value: 'CURTAIN', label: '绐楀笜鎴愬搧', defaultUnit: '绫? },
    { value: 'CURTAIN_FABRIC', label: '绐楀笜闈㈡枡', defaultUnit: '绫? },
    { value: 'WALLCLOTH', label: '澧欏竷', defaultUnit: '骞虫柟绫? },
    { value: 'WALLPAPER', label: '澧欑焊', defaultUnit: '鍗? },
    { value: 'CURTAIN_ACCESSORY', label: '绐楀笜閰嶄欢', defaultUnit: '浠? },
    { value: 'MATTRESS', label: '搴婂灚', defaultUnit: '寮? },
    { value: 'OTHER', label: '鍏朵粬', defaultUnit: '浠? },
] as const;

export const CURTAIN_PATTERN_OPTIONS = [
    '绱犺壊', '鏉＄汗', '鏍煎瓙', '鑺卞崏', '鍑犱綍', '鎻愯姳', '鍗拌姳', '缁ｈ姳', '鍗￠€?, '娓愬彉'
];

export const FABRIC_WIDTH_VALUES = ['140', '145', '150', '200', '250', '270', '280', '300'];
export const WALLPAPER_WIDTH_VALUES = ['53', '60', '70', '90', '100', '106'];
export const WALLPAPER_ROLL_LENGTH_VALUES = ['5', '7', '10', '15', '20', '25'];

export const STYLE_OPTIONS = [
    '鐜颁唬绠€绾?, '鏂颁腑寮?, '娆у紡', '缇庡紡', '鍖楁', '杞诲ア', '鏃ュ紡', '鐢板洯', '鍦颁腑娴?, '宸ヤ笟椋?, '娉曞紡', '涓滃崡浜?
];

interface UseProductFormProps {
    initialData?: Partial<ProductFormValues> & { specs?: Record<string, unknown> };
}

export function useProductForm({ initialData }: UseProductFormProps) {
    const [suppliersList, setSuppliersList] = useState<{ id: string; name: string }[]>([]);
    const [fetchingSuppliers, setFetchingSuppliers] = useState(false);
    const [createSupplierOpen, setCreateSupplierOpen] = useState(false);
    const [attributeSchema, setAttributeSchema] = useState<AttributeField[]>([]);

    const form = useForm<ProductFormValues, unknown, ProductFormValues>({
        resolver: zodResolver(
            initialData?.id ? updateProductSchema : createProductSchema
        ) as Resolver<ProductFormValues>,
        defaultValues: initialData
            ? {
                ...initialData,
                images: initialData.images || [],
                attributes: initialData.specs || {},
                purchasePrice: Number(initialData.purchasePrice) || 0,
                logisticsCost: Number(initialData.logisticsCost) || 0,
                processingCost: Number(initialData.processingCost) || 0,
                lossRate: Number(initialData.lossRate) || 0,
                retailPrice: Number(initialData.retailPrice) || 0,
                floorPrice: Number(initialData.floorPrice) || 0,
            }
            : {
                sku: '',
                name: '',
                category: 'CURTAIN',
                productType: 'FINISHED',
                unit: '绫?,
                purchasePrice: 0,
                logisticsCost: 0,
                processingCost: 0,
                lossRate: 0.05,
                retailPrice: 0,
                floorPrice: 0,
                isToBEnabled: true,
                isToCEnabled: true,
                isStockable: false,
                images: [],
                attributes: {},
            },
    });

    const category = form.watch('category');
    const purchasePrice = form.watch('purchasePrice') || 0;
    const retailPrice = form.watch('retailPrice') || 0;

    // Derived properties for category types
    const isCurtain = category === 'CURTAIN';
    const isCurtainFabric = category === 'CURTAIN_FABRIC';
    const hasCurtainSpecs = isCurtain || isCurtainFabric;
    const isWallcloth = category === 'WALLCLOTH';
    const isWallpaper = category === 'WALLPAPER';
    const hasWidthSpec = hasCurtainSpecs || isWallcloth || isWallpaper;
    const hidePurchaseType = hasCurtainSpecs || isWallcloth || isWallpaper;

    const lossRate = isCurtain ? 0 : form.watch('lossRate') || 0;
    const logisticsCost = Number(form.watch('logisticsCost') || 0);
    const processingCost = isCurtain ? 0 : Number(form.watch('processingCost') || 0);

    // Computed financial metrics
    const totalCost = useMemo(() => {
        return purchasePrice * (1 + lossRate) + logisticsCost + processingCost;
    }, [purchasePrice, lossRate, logisticsCost, processingCost]);

    const grossProfit = useMemo(() => {
        return retailPrice - totalCost;
    }, [retailPrice, totalCost]);

    const grossMargin = useMemo(() => {
        return retailPrice > 0 ? (grossProfit / retailPrice) * 100 : 0;
    }, [grossProfit, retailPrice]);

    // Derived arrays arrays for patterns and styles 
    const currentPatterns: string[] = (form.watch('attributes.patterns') as string[]) || [];
    const currentStyles: string[] = (form.watch('attributes.styles') as string[]) || [];

    const handleCategoryTabChange = useCallback((tabValue: string) => {
        form.setValue('category', tabValue as ProductFormValues['category']);
        const tab = CATEGORY_TABS.find((t) => t.value === tabValue);
        if (tab && !initialData?.id) {
            form.setValue('unit', tab.defaultUnit);
        }

        if (tabValue === 'CURTAIN') {
            form.setValue('productType', 'FINISHED');
            form.setValue('lossRate', 0);
            form.setValue('processingCost', 0);
        }

        if (tabValue === 'CURTAIN_FABRIC' || tabValue === 'WALLCLOTH' || tabValue === 'WALLPAPER') {
            form.setValue('productType', 'CUSTOM');
        }
    }, [form, initialData?.id]);

    const addPattern = useCallback((p: string) => {
        const trimmed = p.trim();
        if (!trimmed || currentPatterns.includes(trimmed)) return;
        form.setValue('attributes.patterns', [...currentPatterns, trimmed]);
    }, [currentPatterns, form]);

    const removePattern = useCallback((p: string) => {
        form.setValue('attributes.patterns', currentPatterns.filter((x) => x !== p));
    }, [currentPatterns, form]);

    const addStyle = useCallback((style: string) => {
        const trimmed = style.trim();
        if (!trimmed || currentStyles.includes(trimmed)) return;
        form.setValue('attributes.styles', [...currentStyles, trimmed]);
    }, [currentStyles, form]);

    const removeStyle = useCallback((style: string) => {
        form.setValue('attributes.styles', currentStyles.filter((s) => s !== style));
    }, [currentStyles, form]);

    const fetchSuppliers = useCallback(async () => {
        setFetchingSuppliers(true);
        try {
            const result = await getSuppliers({ page: 1, pageSize: 100 });
            if (result.error) {
                toast.error(result.error);
                return;
            }
            if (result.data) {
                setSuppliersList(result.data.data);
            }
        } catch (error) {
            logger.error('鑾峰彇渚涘簲鍟嗗垪琛ㄥけ璐?, error);
        } finally {
            setFetchingSuppliers(false);
        }
    }, []);

    const fetchTemplate = useCallback(async () => {
        if (!category) return;
        try {
            const result = await import('../actions').then((mod) =>
                mod.getAttributeTemplate({ category })
            );
            if (result.data?.templateSchema && Array.isArray(result.data.templateSchema)) {
                setAttributeSchema(result.data.templateSchema as AttributeField[]);
            } else {
                setAttributeSchema([]);
            }
        } catch (error) {
            logger.error('鑾峰彇灞炴€фā鏉垮け璐?, error);
        }
    }, [category]);

    useEffect(() => {
        fetchSuppliers();
    }, [fetchSuppliers]);

    useEffect(() => {
        fetchTemplate();
    }, [fetchTemplate]);

    return {
        form,
        category,
        isCurtain,
        isCurtainFabric,
        hasCurtainSpecs,
        isWallcloth,
        isWallpaper,
        hasWidthSpec,
        hidePurchaseType,
        totalCost,
        grossProfit,
        grossMargin,
        suppliersList,
        fetchingSuppliers,
        createSupplierOpen,
        setCreateSupplierOpen,
        attributeSchema,
        currentPatterns,
        currentStyles,
        fetchSuppliers,
        handleCategoryTabChange,
        addPattern,
        removePattern,
        addStyle,
        removeStyle,
    };
}
